import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath, pathToFileURL } from "node:url";
import { createHash } from "node:crypto";
import ts from "typescript";
import prettier from "prettier";

const GENERATED_HEADER = `// This file is generated by scripts/sync-template-config.mjs.
// Do not edit it manually.

`;

export function toRustString(value) {
  return String(value)
    .replace(/\\/g, "\\\\")
    .replace(/"/g, '\\"')
    .replace(/\n/g, "\\n");
}

export function toCargoLibName(packageName) {
  return packageName.replace(/-/g, "_");
}

export function validateTemplateConfig(config) {
  const errors = [];

  const requiredStringFields = [
    "appName",
    "packageName",
    "productName",
    "identifier",
    "description",
    "repositoryUrl",
    "deepLinkScheme",
    "updaterEndpoint",
  ];

  for (const field of requiredStringFields) {
    if (typeof config[field] !== "string" || config[field].trim() === "") {
      errors.push(`${field} must be a non-empty string`);
    }
  }

  if (
    typeof config.packageName === "string" &&
    !/^[a-z0-9][a-z0-9-]*[a-z0-9]$/.test(config.packageName)
  ) {
    errors.push("packageName must be kebab-case, for example desktop-shell");
  }

  if (
    typeof config.identifier === "string" &&
    !/^[A-Za-z][A-Za-z0-9_-]*(\.[A-Za-z0-9][A-Za-z0-9_-]*)+$/.test(
      config.identifier,
    )
  ) {
    errors.push("identifier must look like com.example.desktop-shell");
  }

  if (
    typeof config.deepLinkScheme === "string" &&
    !/^[a-z][a-z0-9+.-]*$/.test(config.deepLinkScheme)
  ) {
    errors.push("deepLinkScheme must be a valid lowercase URL scheme");
  }

  if (
    typeof config.repositoryUrl === "string" &&
    !/^https:\/\/.+/.test(config.repositoryUrl)
  ) {
    errors.push("repositoryUrl must be an https url");
  }

  if (
    typeof config.updaterEndpoint === "string" &&
    !/^https:\/\/.+/.test(config.updaterEndpoint)
  ) {
    errors.push("updaterEndpoint must be an https url");
  }

  return errors;
}

export async function loadTemplateConfig(root = process.cwd()) {
  const configPath = join(root, "template.config.ts");

  if (!existsSync(configPath)) {
    throw new Error("template.config.ts is missing");
  }

  const source = readFileSync(configPath, "utf8");
  const transpiled = ts.transpileModule(source, {
    compilerOptions: {
      module: ts.ModuleKind.ES2022,
      target: ts.ScriptTarget.ES2022,
      esModuleInterop: true,
    },
  }).outputText;

  const hash = createHash("sha256")
    .update(configPath + transpiled)
    .digest("hex");
  const dataUrl = `data:text/javascript;base64,${Buffer.from(
    `${transpiled}\n//# sourceURL=${pathToFileURL(configPath).href}?v=${hash}`,
  ).toString("base64")}`;

  const module = await import(dataUrl);
  const config = module.default;

  const errors = validateTemplateConfig(config);

  if (errors.length > 0) {
    throw new Error(
      `Invalid template.config.ts:\n${errors.map((error) => `- ${error}`).join("\n")}`,
    );
  }

  return config;
}

function readJson(path) {
  return JSON.parse(readFileSync(path, "utf8"));
}

function formatJson(value) {
  return `${JSON.stringify(value, null, 2)}\n`;
}

function ensureParent(path) {
  mkdirSync(dirname(path), { recursive: true });
}

function prettierParserForPath(path) {
  if (path.endsWith(".ts")) {
    return "typescript";
  }

  if (path.endsWith(".md")) {
    return "markdown";
  }

  return undefined;
}

async function formatGeneratedText(path, content) {
  const parser = prettierParserForPath(path);

  if (!parser) {
    return content;
  }

  return prettier.format(content, { parser });
}

async function writeText(path, content, options) {
  ensureParent(path);

  const formattedContent = await formatGeneratedText(path, content);

  if (options.check) {
    const current = existsSync(path) ? readFileSync(path, "utf8") : null;

    if (current !== formattedContent) {
      options.violations.push(`${path} is not synced with template.config.ts`);
    }

    return;
  }

  writeFileSync(path, formattedContent, "utf8");
}

async function writeJson(path, value, options) {
  await writeText(path, formatJson(value), options);
}

export function updatePackageJson(packageJson, config) {
  const next = structuredClone(packageJson);

  next.name = config.packageName;
  next.description = config.description;

  next.repository = {
    type: "git",
    url: config.repositoryUrl,
  };

  next.scripts = {
    ...(next.scripts ?? {}),
    "sync:template": "node scripts/sync-template-config.mjs",
    "check:template-config": "node scripts/sync-template-config.mjs --check",
  };

  return next;
}

function replaceTomlStringValue(content, key, value) {
  const escaped = String(value).replace(/\\/g, "\\\\").replace(/"/g, '\\"');
  const pattern = new RegExp(`^${key}\\s*=\\s*".*"$`, "m");

  if (pattern.test(content)) {
    return content.replace(pattern, `${key} = "${escaped}"`);
  }

  return `${content.trimEnd()}\n${key} = "${escaped}"\n`;
}

function replaceTomlStringValueInSection(content, section, key, value) {
  const escaped = String(value).replace(/\\/g, "\\\\").replace(/"/g, '\\"');
  const escapedSection = section.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const sectionHeader = new RegExp(`^\\[${escapedSection}\\]$`, "m");
  const headerMatch = sectionHeader.exec(content);

  if (!headerMatch) {
    return content;
  }

  const startIndex = headerMatch.index + headerMatch[0].length;
  const nextSection = content.slice(startIndex).search(/^\[/m);
  const endIndex =
    nextSection === -1 ? content.length : startIndex + nextSection;

  const before = content.slice(0, startIndex);
  const body = content.slice(startIndex, endIndex);
  const after = content.slice(endIndex);

  const updatedBody = replaceTomlStringValue(body, key, value);

  return before + updatedBody + after;
}

function ensureCargoLibSection(content, packageName) {
  const libName = toCargoLibName(packageName);

  if (/\[lib\]/.test(content)) {
    return replaceTomlStringValueInSection(content, "lib", "name", libName);
  }

  return `${content.trimEnd()}

[lib]
name = "${libName}"
path = "src/lib.rs"
`;
}

export function updateCargoToml(content, config) {
  let next = content;

  next = replaceTomlStringValue(next, "name", config.packageName);
  next = replaceTomlStringValue(next, "description", config.description);
  next = ensureCargoLibSection(next, config.packageName);

  return next;
}

export function updateTauriConfig(tauriConfig, config) {
  const next = structuredClone(tauriConfig);

  next.productName = config.productName;
  next.identifier = config.identifier;

  next.app = next.app ?? {};
  next.app.windows = Array.isArray(next.app.windows) ? next.app.windows : [];

  if (next.app.windows.length === 0) {
    next.app.windows.push({
      title: config.productName,
      width: 1000,
      height: 650,
      minWidth: 900,
      minHeight: 600,
    });
  } else {
    // The shell template ships the main window with `title: ""` and
    // `titleBarStyle: "Overlay"` so the renderer can paint its own
    // brand row on macOS. In that case the shell owns the title and
    // the template should not overwrite it back to `productName` on
    // every sync.
    const [mainWindow, ...rest] = next.app.windows;
    const shellOwnedTitle =
      mainWindow?.titleBarStyle === "Overlay" && mainWindow?.title === "";

    next.app.windows = [
      {
        ...mainWindow,
        ...(shellOwnedTitle ? {} : { title: config.productName }),
      },
      ...rest,
    ];
  }

  next.plugins = next.plugins ?? {};
  next.plugins.updater = next.plugins.updater ?? {};
  next.plugins.updater.endpoints = [config.updaterEndpoint];

  return next;
}

export function renderFrontendTemplateConfig(config) {
  return `${GENERATED_HEADER}export const TEMPLATE_CONFIG = ${JSON.stringify(config, null, 2)} as const

export type TemplateConfig = typeof TEMPLATE_CONFIG
`;
}

export function renderFrontendBrand() {
  return `${GENERATED_HEADER}import { TEMPLATE_CONFIG } from './templateConfig'

export const APP_BRAND = {
  displayName: TEMPLATE_CONFIG.appName,
  packageName: TEMPLATE_CONFIG.packageName,
  productName: TEMPLATE_CONFIG.productName,
  description: TEMPLATE_CONFIG.description,
  repositoryUrl: TEMPLATE_CONFIG.repositoryUrl,
  windowTitle: TEMPLATE_CONFIG.productName,
  identifier: TEMPLATE_CONFIG.identifier,
  deepLinkScheme: TEMPLATE_CONFIG.deepLinkScheme,
  updaterEndpoint: TEMPLATE_CONFIG.updaterEndpoint,
} as const

export type AppBrand = typeof APP_BRAND

export function formatAppTitle(section?: string): string {
  if (!section?.trim()) {
    return APP_BRAND.windowTitle
  }

  return \`\${section.trim()} - \${APP_BRAND.windowTitle}\`
}
`;
}

export function renderFrontendSettings() {
  return `${GENERATED_HEADER}import { APP_BRAND } from '../brand/brand'

export type ThemeMode = 'system' | 'light' | 'dark'

export interface ShellSettings {
  theme: ThemeMode
  startMinimized: boolean
}

export const defaultShellSettings: ShellSettings = {
  theme: 'system',
  startMinimized: false,
}

export const SETTINGS_STORAGE_KEY = \`\${APP_BRAND.packageName}.settings\`
export const THEME_STORAGE_KEY = \`\${APP_BRAND.packageName}.theme\`
`;
}

export function renderRustBrand(config) {
  return `// This file is generated by scripts/sync-template-config.mjs.
// Do not edit it manually.

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct AppBrand {
    pub app_name: &'static str,
    pub package_name: &'static str,
    pub product_name: &'static str,
    pub description: &'static str,
    pub identifier: &'static str,
    pub repository_url: &'static str,
    pub deep_link_scheme: &'static str,
    pub updater_endpoint: &'static str,
    pub config_dir_name: &'static str,
    pub settings_file_name: &'static str,
    pub database_file_name: &'static str,
    pub log_file_name: &'static str,
    pub tray_tooltip: &'static str,
    pub window_title: &'static str,
}

pub const APP_BRAND: AppBrand = AppBrand {
    app_name: "${toRustString(config.appName)}",
    package_name: "${toRustString(config.packageName)}",
    product_name: "${toRustString(config.productName)}",
    description: "${toRustString(config.description)}",
    identifier: "${toRustString(config.identifier)}",
    repository_url: "${toRustString(config.repositoryUrl)}",
    deep_link_scheme: "${toRustString(config.deepLinkScheme)}",
    updater_endpoint:
        "${toRustString(config.updaterEndpoint)}",
    config_dir_name: "${toRustString(config.packageName)}",
    settings_file_name: "shell-settings.json",
    database_file_name: "${toRustString(config.packageName)}.db",
    log_file_name: "${toRustString(config.packageName)}.log",
    tray_tooltip: "${toRustString(config.productName)}",
    window_title: "${toRustString(config.productName)}",
};

pub fn app_title(section: Option<&str>) -> String {
    match section {
        Some(section) if !section.trim().is_empty() => {
            format!("{} - {}", section.trim(), APP_BRAND.window_title)
        }
        _ => APP_BRAND.window_title.to_string(),
    }
}

pub fn brand_values() -> Vec<&'static str> {
    vec![
        APP_BRAND.app_name,
        APP_BRAND.package_name,
        APP_BRAND.product_name,
        APP_BRAND.description,
        APP_BRAND.identifier,
        APP_BRAND.repository_url,
        APP_BRAND.deep_link_scheme,
        APP_BRAND.updater_endpoint,
        APP_BRAND.config_dir_name,
        APP_BRAND.settings_file_name,
        APP_BRAND.database_file_name,
        APP_BRAND.log_file_name,
        APP_BRAND.tray_tooltip,
        APP_BRAND.window_title,
    ]
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn brand_should_have_required_identity() {
        assert!(!APP_BRAND.app_name.is_empty());
        assert!(!APP_BRAND.package_name.is_empty());
        assert!(!APP_BRAND.identifier.is_empty());
        assert!(!APP_BRAND.repository_url.is_empty());
        assert!(!APP_BRAND.updater_endpoint.is_empty());
    }

    #[test]
    fn app_title_should_format_section() {
        assert_eq!(app_title(None), APP_BRAND.window_title);
        assert_eq!(
            app_title(Some("Settings")),
            format!("Settings - {}", APP_BRAND.window_title)
        );
    }
}
`;
}

function upsertReadmeTemplateIdentity(readme, config) {
  const start = "<!-- TEMPLATE_IDENTITY_START -->";
  const end = "<!-- TEMPLATE_IDENTITY_END -->";

  const block = `${start}
## Template Identity

| Field | Value |
| --- | --- |
| App Name | ${config.appName} |
| Package Name | ${config.packageName} |
| Product Name | ${config.productName} |
| Identifier | ${config.identifier} |
| Repository | ${config.repositoryUrl} |
| Deep Link Scheme | ${config.deepLinkScheme} |
| Updater Endpoint | ${config.updaterEndpoint} |

To change the application identity, edit \`template.config.ts\` and run:

\`\`\`bash
pnpm sync:template
\`\`\`
${end}`;

  if (readme.includes(start) && readme.includes(end)) {
    const pattern = new RegExp(`${start}[\\s\\S]*?${end}`);
    return readme.replace(pattern, block);
  }

  return `${readme.trimEnd()}

${block}
`;
}

export async function syncTemplateConfig(root, config, options = {}) {
  const state = {
    check: Boolean(options.check),
    violations: [],
  };

  const packageJsonPath = join(root, "package.json");
  const cargoTomlPath = join(root, "src-tauri", "Cargo.toml");
  const tauriConfigPath = join(root, "src-tauri", "tauri.conf.json");
  const readmePath = join(root, "README.md");

  const packageJson = readJson(packageJsonPath);
  await writeJson(
    packageJsonPath,
    updatePackageJson(packageJson, config),
    state,
  );

  const cargoToml = readFileSync(cargoTomlPath, "utf8");
  await writeText(cargoTomlPath, updateCargoToml(cargoToml, config), state);

  const tauriConfig = readJson(tauriConfigPath);
  await writeJson(
    tauriConfigPath,
    updateTauriConfig(tauriConfig, config),
    state,
  );

  const readme = existsSync(readmePath)
    ? readFileSync(readmePath, "utf8")
    : `# ${config.productName}\n`;
  await writeText(
    readmePath,
    upsertReadmeTemplateIdentity(readme, config),
    state,
  );

  await writeText(
    join(root, "src/lib/brand/templateConfig.ts"),
    renderFrontendTemplateConfig(config),
    state,
  );

  await writeText(
    join(root, "src/lib/brand/brand.ts"),
    renderFrontendBrand(),
    state,
  );
  await writeText(
    join(root, "src/lib/settings/settings.ts"),
    renderFrontendSettings(),
    state,
  );

  await writeText(
    join(root, "src-tauri/src/shell/brand.rs"),
    renderRustBrand(config),
    state,
  );

  return state.violations;
}

export async function runCli() {
  const root = process.cwd();
  const check = process.argv.includes("--check");
  const config = await loadTemplateConfig(root);
  const violations = await syncTemplateConfig(root, config, { check });

  if (violations.length > 0) {
    console.error("Template config is not synced:");
    for (const violation of violations) {
      console.error(`- ${violation}`);
    }
    process.exitCode = 1;
    return;
  }

  if (check) {
    console.log("Template config check passed.");
  } else {
    console.log("Template config synced.");
  }
}

const currentFile = fileURLToPath(import.meta.url);

if (process.argv[1] === currentFile) {
  runCli().catch((error) => {
    console.error(error);
    process.exitCode = 1;
  });
}
